(function () {
  // Analysis viewer client: interactions, legend, highlight, exports.
  // Assumes HTML was generated by analysis.viewer with external CSS and this JS.

  const svg = document.querySelector("svg");
  if (!svg) return;

  // DOM references
  const conv = document.getElementById("conv");
  const who = document.getElementById("who");
  const md = document.getElementById("md");
  const legend = document.getElementById("legend");

  // Selection state
  let currentPid = null;
  let lastX = null;
  let lockSelection = false;
  // When true, do not auto-scroll the conversation panel
  let suppressAutoScroll = false;

  // Emphasize currently selected participant
  function emphasize() {
    document.querySelectorAll(".trace").forEach((tr) => {
      const on = currentPid !== null && tr.dataset.pid === String(currentPid);
      tr.classList.toggle("active", on);
      tr.classList.toggle("dim", currentPid !== null && !on);
    });
    document.querySelectorAll(".mk").forEach((mk) => {
      const on = currentPid !== null && mk.dataset.pid === String(currentPid);
      mk.classList.toggle("active", on);
      mk.classList.toggle("dim", currentPid !== null && !on);
    });
    // Dim point circles for non-selected participants as well
    document.querySelectorAll(".pt").forEach((pt) => {
      const on = currentPid !== null && pt.dataset.pid === String(currentPid);
      pt.classList.toggle("active", on);
      pt.classList.toggle("dim", currentPid !== null && !on);
    });
  }

  // Cursor line over SVG for mouse position highlight
  const NS = "http://www.w3.org/2000/svg";
  const cursor = document.createElementNS(NS, "line");
  cursor.setAttribute("id", "cursor");
  cursor.setAttribute("stroke", "#111");
  cursor.setAttribute("stroke-width", "1");
  cursor.setAttribute("opacity", "0.6");
  svg.appendChild(cursor);

  // Show conversation for a given participant id
  function show(pid) {
    const tpl = document.getElementById("conv-" + pid);
    if (!tpl) return;
    const frag = tpl.content.cloneNode(true);
    const summaryEl = frag.querySelector(".summary-md");
    const msgs = frag.querySelector(".msgs");
    conv.innerHTML = "";
    if (msgs) conv.appendChild(msgs);
    md.innerHTML = summaryEl ? summaryEl.innerHTML : "";
    who.textContent = "Showing: Participant " + (Number(pid) + 1);
    currentPid = String(pid);
    emphasize();
    if (lastX !== null) highlightForX(lastX);
  }

  function clearHL() {
    document
      .querySelectorAll("#conv .msg.hl")
      .forEach((el) => el.classList.remove("hl"));
    document
      .querySelectorAll("#conv .tok.whl")
      .forEach((el) => el.classList.remove("whl"));
  }
  function highlightMsgByRec(recIdx) {
    clearHL();
    const el = document.querySelector(
      '#conv .msg[data-rec-idx="' + recIdx + '"]',
    );
    if (el) {
      el.classList.add("hl");
      if (!suppressAutoScroll) {
        el.scrollIntoView({ block: "nearest" });
      }
    }
  }
  function highlightMsgWord(recIdx, frac) {
    const m = document.querySelector(
      '#conv .msg[data-rec-idx="' + recIdx + '"]',
    );
    if (!m) {
      highlightMsgByRec(recIdx);
      return;
    }
    const dur = Number(m.dataset.duration);
    if (!Number.isFinite(dur) || dur <= 0) {
      highlightMsgByRec(recIdx);
      return;
    }
    const t = Math.max(0, Math.min(1, frac)) * dur;
    let best = null;
    document
      .querySelectorAll('#conv .msg[data-rec-idx="' + recIdx + '"] .tok')
      .forEach((tok) => {
        const ws = Number(tok.dataset.wstart),
          we = Number(tok.dataset.wend);
        if (Number.isFinite(ws) && Number.isFinite(we) && ws <= t && t < we)
          best = tok;
      });
    clearHL();
    if (best) {
      best.classList.add("whl");
      m.classList.add("hl");
      if (!suppressAutoScroll) {
        m.scrollIntoView({ block: "nearest" });
      }
    } else highlightMsgByRec(recIdx);
  }

  // Convert domain X to SVG x in pixels
  function domainToSvgX(dx) {
    const x0 = Number(svg.dataset.x0),
      x1 = Number(svg.dataset.x1);
    const ml = Number(svg.dataset.ml),
      w = Number(svg.dataset.w);
    return ml + ((dx - x0) / (x1 - x0)) * w;
  }
  function svgX(evt) {
    const pt = svg.createSVGPoint();
    pt.x = evt.clientX;
    pt.y = evt.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse()).x;
  }
  // Move highlights based on an SVG x coordinate (pixels)
  function highlightForX(x) {
    if (currentPid === null) return;
    lastX = x;
    const x0 = Number(svg.dataset.x0),
      x1 = Number(svg.dataset.x1);
    const ml = Number(svg.dataset.ml),
      mt = Number(svg.dataset.mt);
    const h = Number(svg.dataset.h);
    const w = Number(svg.dataset.w);
    const domainX = x0 + Math.max(0, Math.min(1, (x - ml) / w)) * (x1 - x0);
    const connect = svg.dataset.connect === "true";
    const yTop = mt,
      yBot = mt + h;
    cursor.setAttribute("x1", x);
    cursor.setAttribute("x2", x);
    cursor.setAttribute("y1", yTop);
    cursor.setAttribute("y2", yBot);
    const nRec = document.querySelectorAll("#conv .msg[data-rec-idx]").length;
    if (nRec <= 0) {
      clearHL();
      return;
    }
    if (connect) {
      const idx = Math.round(domainX);
      if (!Number.isFinite(idx) || idx < 1 || idx > nRec) {
        clearHL();
        return;
      }
      highlightMsgByRec(idx);
    } else {
      const offset = Number(svg.dataset.offset) || 1;
      const segFloat = domainX - offset;
      const seg = Math.floor(segFloat) + 1;
      const frac = Math.max(0, Math.min(1, segFloat - Math.floor(segFloat)));
      if (!Number.isFinite(seg) || seg < 1 || seg > nRec) {
        clearHL();
        return;
      }
      highlightMsgWord(seg, frac);
    }
  }

  function bindParticipantEvents(el) {
    const pid = el.dataset.pid;
    el.addEventListener("mouseenter", () => {
      if (!lockSelection) show(pid);
    });
    el.addEventListener("click", () => {
      lockSelection = true;
      show(pid);
    });
  }

  // Bind traces and hit areas
  document.querySelectorAll(".trace").forEach(bindParticipantEvents);
  document.querySelectorAll(".hit").forEach(bindParticipantEvents);

  // Marker legend
  (function () {
    function createLegendItem(className, text) {
      const item = document.createElement("div");
      item.className = "item";
      const swatch = document.createElement("span");
      swatch.className = "sw " + className;
      const label = document.createElement("span");
      label.textContent = text;
      item.appendChild(swatch);
      item.appendChild(label);
      legend.appendChild(item);
    }

    createLegendItem("mk-sq", "initial belief");
    createLegendItem("mk-dmd", "final belief");
  })();
  (function () {
    const seen = new Set();
    document.querySelectorAll(".trace").forEach((tr) => {
      const pid = tr.dataset.pid;
      if (seen.has(pid)) return;
      seen.add(pid);
      const m = tr.getAttribute("style").match(/stroke:([^;]+)/);
      const color = m && m[1] ? m[1] : "#666";
      const el = document.createElement("div");
      el.className = "item";
      el.dataset.pid = pid;
      const sw = document.createElement("span");
      sw.className = "sw";
      sw.style.background = color;
      sw.style.borderColor = "rgba(0,0,0,0.4)";
      const lab = document.createElement("span");
      lab.textContent = "ppt " + (Number(pid) + 1);
      el.appendChild(sw);
      el.appendChild(lab);
      legend.appendChild(el);
    });
    legend.addEventListener("click", (e) => {
      const it = e.target.closest(".item");
      if (!it) return;
      lockSelection = true;
      show(it.dataset.pid);
    });
  })();

  // Reset
  const btnReset = document.getElementById("btn-reset");
  if (btnReset) {
    btnReset.addEventListener("click", () => {
      lockSelection = false;
      currentPid = null;
      lastX = null;
      who.textContent = "Hover a line to see that conversation.";
      conv.innerHTML = "";
      md.innerHTML = "";
      document.querySelectorAll(".trace").forEach((tr) => {
        tr.classList.remove("active", "dim");
      });
      document.querySelectorAll(".mk").forEach((mk) => {
        mk.classList.remove("active", "dim");
      });
      document.querySelectorAll(".pt").forEach((pt) => {
        pt.classList.remove("active", "dim");
      });
      cursor.setAttribute("opacity", "0");
    });
  }

  // Export
  function download(name, href) {
    const a = document.createElement("a");
    a.href = href;
    a.download = name;
    document.body.appendChild(a);
    a.click();
    a.remove();
  }
  function addExportLegend(clone) {
    // Place legend to the right of the plot area and expand the SVG as needed
    const g = document.createElementNS(NS, "g");
    g.setAttribute("id", "export-legend");
    const boxW = 12;
    const lineH = 14;

    // Current svg dimensions (fallback to viewBox if needed)
    const vb = (clone.getAttribute("viewBox") || "").split(/\s+/).map(Number);
    let curW = parseInt(clone.getAttribute("width"));
    let curH = parseInt(clone.getAttribute("height"));
    if (!Number.isFinite(curW) && vb.length === 4) curW = vb[2];
    if (!Number.isFinite(curH) && vb.length === 4) curH = vb[3];

    // Plot geometry from data attrs
    const ml = Number(clone.dataset.ml) || 0;
    const mr = Number(clone.dataset.mr) || 0;
    const wPlot = Number(clone.dataset.w) || Math.max(0, curW - ml - mr);
    const pad = 16; // spacing between plot and legend
    const legendMinW = 180; // allocate enough space for labels

    // Legend anchor position and ensure SVG width fits it
    const x = Math.round(ml + wPlot + pad);
    let y = 18;
    const neededW = x + legendMinW + pad;
    const newW = Math.max(curW || 0, neededW);
    if (Number.isFinite(newW) && newW > (curW || 0)) {
      clone.setAttribute("width", String(newW));
      // Expand viewBox width to match when present
      if (vb.length === 4) {
        vb[2] = newW;
        clone.setAttribute("viewBox", vb.join(" "));
      }
    }
    const sq = document.createElementNS(NS, "rect");
    sq.setAttribute("x", x);
    sq.setAttribute("y", y - 10);
    sq.setAttribute("width", boxW);
    sq.setAttribute("height", boxW);
    sq.setAttribute("fill", "#fff");
    sq.setAttribute("stroke", "#111");
    sq.setAttribute("stroke-width", "1.2");
    g.appendChild(sq);
    const txs = document.createElementNS(NS, "text");
    txs.setAttribute("x", x + boxW + 6);
    txs.setAttribute("y", y);
    txs.setAttribute("font-size", "12");
    txs.textContent = "initial belief";
    g.appendChild(txs);
    y += lineH;
    const dmd = document.createElementNS(NS, "polygon");
    const cx = x + boxW / 2,
      cy = y - 6,
      size = boxW;
    const pts = [
      cx + 0,
      cy - size / 2,
      cx + size / 2,
      cy + 0,
      cx + 0,
      cy + size / 2,
      cx - size / 2,
      cy + 0,
    ].join(" ");
    dmd.setAttribute("points", pts);
    dmd.setAttribute("fill", "#111");
    dmd.setAttribute("stroke", "#111");
    dmd.setAttribute("stroke-width", "0.8");
    g.appendChild(dmd);
    const txd = document.createElementNS(NS, "text");
    txd.setAttribute("x", x + boxW + 6);
    txd.setAttribute("y", y);
    txd.setAttribute("font-size", "12");
    txd.textContent = "final belief";
    g.appendChild(txd);
    y += lineH;
    const t = document.createElementNS(NS, "text");
    t.setAttribute("x", x);
    t.setAttribute("y", y);
    t.setAttribute("font-size", "12");
    t.textContent = "ppt ids";
    g.appendChild(t);
    y += lineH;
    const seen = new Set();
    clone.querySelectorAll(".trace").forEach((tr) => {
      const pid = tr.dataset.pid;
      if (seen.has(pid)) return;
      seen.add(pid);
      const m = tr.getAttribute("style").match(/stroke:([^;]+)/);
      const color = m && m[1] ? m[1] : "#666";
      const r = document.createElementNS(NS, "rect");
      r.setAttribute("x", x);
      r.setAttribute("y", y - 10);
      r.setAttribute("width", boxW);
      r.setAttribute("height", boxW);
      r.setAttribute("fill", color);
      r.setAttribute("stroke", "rgba(0,0,0,0.5)");
      g.appendChild(r);
      const tx = document.createElementNS(NS, "text");
      tx.setAttribute("x", x + boxW + 6);
      tx.setAttribute("y", y);
      tx.setAttribute("font-size", "12");
      tx.textContent = "ppt " + (Number(pid) + 1);
      g.appendChild(tx);
      y += lineH;
    });
    clone.appendChild(g);
  }
  function exportSVG() {
    const clone = svg.cloneNode(true);
    addExportLegend(clone);
    const xml = new XMLSerializer().serializeToString(clone);
    const blob = new Blob([xml], { type: "image/svg+xml;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    download("chart.svg", url);
    setTimeout(() => URL.revokeObjectURL(url), 1000);
  }
  function exportPNG() {
    const clone = svg.cloneNode(true);
    addExportLegend(clone);
    // Use the possibly-expanded clone dimensions
    const vb = (clone.getAttribute("viewBox") || "").split(/\s+/).map(Number);
    let w = parseInt(clone.getAttribute("width"));
    let h = parseInt(clone.getAttribute("height"));
    if (!Number.isFinite(w) && vb.length === 4) w = vb[2];
    if (!Number.isFinite(h) && vb.length === 4) h = vb[3];

    const xml = new XMLSerializer().serializeToString(clone);
    const img = new Image();
    const canv = document.createElement("canvas");
    canv.width = w;
    canv.height = h;
    const ctx = canv.getContext("2d");
    img.onload = () => {
      ctx.clearRect(0, 0, w, h);
      ctx.drawImage(img, 0, 0);
      download("chart.png", canv.toDataURL("image/png"));
    };
    img.src = "data:image/svg+xml;charset=utf-8," + encodeURIComponent(xml);
  }
  function exportPDF() {
    const w = window.open("", "_blank");
    if (!w) return;
    const clone = svg.cloneNode(true);
    addExportLegend(clone);
    w.document.open();
    w.document.write(clone.outerHTML);
    w.document.close();
    w.focus();
    setTimeout(() => w.print(), 50);
  }
  const btnSvg = document.getElementById("btn-svg");
  const btnPng = document.getElementById("btn-png");
  const btnPdf = document.getElementById("btn-pdf");
  if (btnSvg) btnSvg.addEventListener("click", exportSVG);
  if (btnPng) btnPng.addEventListener("click", exportPNG);
  if (btnPdf) btnPdf.addEventListener("click", exportPDF);

  // Relative toggle
  const toggleRel = document.getElementById("toggle-rel");
  if (toggleRel) {
    toggleRel.checked = svg.dataset.rel === "true";
    function updateRelMode(useRel) {
      document.querySelectorAll(".trace").forEach((tr) => {
        const d = useRel ? tr.dataset.rel : tr.dataset.raw;
        if (d) tr.setAttribute("points", d);
      });
      document.querySelectorAll("circle.pt").forEach((c) => c.remove());
      document.querySelectorAll(".trace").forEach((tr) => {
        const color =
          (tr.getAttribute("style").match(/stroke:([^;]+)/) || [])[1] || "#666";
        const pts = (tr.getAttribute("points") || "").trim().split(/\s+/);
        pts.forEach((p) => {
          const xy = p.split(",");
          if (xy.length === 2) {
            const c = document.createElementNS(NS, "circle");
            c.setAttribute("class", "pt");
            c.dataset.pid = tr.dataset.pid || "";
            c.setAttribute("cx", xy[0]);
            c.setAttribute("cy", xy[1]);
            c.setAttribute("r", "2.2");
            c.setAttribute("fill", color);
            c.setAttribute("fill-opacity", "0.7");
            svg.appendChild(c);
          }
        });
      });
      // Update initial/final markers to match relative or raw mode
      document.querySelectorAll(".mk").forEach((mk) => {
        const cx = Number(mk.dataset.cx);
        const size = Number(mk.dataset.size || 0);
        const cy = Number(useRel ? mk.dataset.cyRel : mk.dataset.cyRaw);
        if (
          !Number.isFinite(cx) ||
          !Number.isFinite(cy) ||
          !Number.isFinite(size)
        )
          return;
        if (mk.classList.contains("mk-init")) {
          mk.setAttribute("x", (cx - size / 2).toFixed(2));
          mk.setAttribute("y", (cy - size / 2).toFixed(2));
        } else if (mk.classList.contains("mk-final")) {
          const pts = [
            [cx, cy - size / 2],
            [cx + size / 2, cy],
            [cx, cy + size / 2],
            [cx - size / 2, cy],
          ]
            .map(([x, y]) => `${x.toFixed(2)},${y.toFixed(2)}`)
            .join(" ");
          mk.setAttribute("points", pts);
        }
      });
      svg.dataset.rel = useRel ? "true" : "false";
      // Re-apply emphasis so regenerated points inherit dimming
      emphasize();
    }
    toggleRel.addEventListener("change", () => {
      updateRelMode(toggleRel.checked);
    });
  }

  // Reverse highlight from message hover
  conv.addEventListener("mousemove", (e) => {
    const m = e.target.closest(".msg");
    if (!m || currentPid === null) return;
    const recAttr = m.getAttribute("data-rec-idx");
    if (!recAttr) return;
    const rec = Number(recAttr);
    if (!Number.isFinite(rec) || rec <= 0) return;
    const connect = svg.dataset.connect === "true";
    let dx;
    if (connect) {
      dx = rec;
    } else {
      const offset = Number(svg.dataset.offset) || 1;
      let frac = 0.5;
      const dur = Number(m.dataset.duration);
      if (Number.isFinite(dur) && dur > 0) {
        const tok = e.target.closest(".tok");
        if (tok) {
          const ws = Number(tok.dataset.wstart),
            we = Number(tok.dataset.wend);
          if (Number.isFinite(ws) && Number.isFinite(we)) {
            const mid = (ws + we) / 2;
            frac = Math.max(0, Math.min(1, mid / dur));
          }
        }
      }
      dx = offset + (rec - 1) + frac;
    }
    emphasize();
    highlightForX(domainToSvgX(dx));
  });
  conv.addEventListener("mouseenter", () => {
    suppressAutoScroll = true;
  });
  conv.addEventListener("mouseleave", () => {
    suppressAutoScroll = false;
  });
  svg.addEventListener("mousemove", (evt) => {
    highlightForX(svgX(evt));
  });
  svg.addEventListener("mouseleave", () => {
    lastX = null;
    clearHL();
  });

  // Layout: keep both areas in view
  function layoutHeights() {
    const chart = document.getElementById("chartrow");
    const top = chart ? chart.getBoundingClientRect().top : 0;
    const total = Math.max(300, window.innerHeight - top - 8);
    const svgH = Math.max(240, Math.floor(total / 2));
    svg.style.height = svgH + "px";
    const convTop = conv.getBoundingClientRect().top;
    const rest = Math.max(160, window.innerHeight - convTop - 8);
    conv.style.height = rest + "px";
  }
  layoutHeights();
  window.addEventListener("resize", layoutHeights);
})();
